const clientsData = $input.first().json;
const clients = (clientsData.list || []).filter(c => c.notification_email && c.notification_email.trim());
if (!clients.length) return [];

// 16-min window to slightly overlap with 15-min schedule
const cutoff = new Date(Date.now() - 16 * 60 * 1000).toISOString();
return clients.map(c => ({ json: { ...c, _cutoff: cutoff } }));

const client = $('Loop clients').first().json;
const hotData = $('HTTP · Get hot leads').first().json;
const handoverData = $('HTTP · Get handovers').first().json;
const hotLeads = hotData.list || [];
const handovers = handoverData.list || [];

const alerts = [];
hotLeads.forEach(l => {
  const phone = String(l.Phone||'');
  const masked = phone.length > 4 ? phone.slice(0,2)+'***'+phone.slice(-2) : phone;
  alerts.push({
    subject: '🔥 Hot lead: ' + (l.Name||'Unknown'),
    body: `A hot buying signal was detected.\n\nLead: ${l.Name||'Unknown'}\nPhone: ${masked}\nStage: ${l.Stage||'new'}\nSignal: ${l.HotMomentText||'Buying keyword detected'}\nClient: ${client.client_name}\nTime: ${new Date(l.LastMsgAt||l.Date).toLocaleString()}\n\nOpen your dashboard to follow up.`,
    to: client.notification_email
  });
});
handovers.forEach(l => {
  const phone = String(l.Phone||'');
  const masked = phone.length > 4 ? phone.slice(0,2)+'***'+phone.slice(-2) : phone;
  alerts.push({
    subject: '🙋 Human handover: ' + (l.Name||'Unknown'),
    body: `A lead has requested human assistance.\n\nLead: ${l.Name||'Unknown'}\nPhone: ${masked}\nClient: ${client.client_name}\nTime: ${new Date(l.Date).toLocaleString()}\n\nOpen your dashboard to take over the conversation.`,
    to: client.notification_email
  });
});

return alerts.map(a => ({ json: a }));
